import{_ as e,a as t,b as l,c as o}from"./chunks/下载好后的视频.pSSnkGgz.js";import{_ as n,o as i,c as r,a2 as d}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Magnet Transfer","description":"","frontmatter":{},"headers":[],"relativePath":"my/Other/magnet-transfer.md","filePath":"my/Other/magnet-transfer.md","lastUpdated":1781962217000}'),s={name:"my/Other/magnet-transfer.md"};function p(m,a,c,h,u,g){return i(),r("div",null,[...a[0]||(a[0]=[d('<h1 id="magnet-transfer" tabindex="-1">Magnet Transfer <a class="header-anchor" href="#magnet-transfer" aria-label="Permalink to &quot;Magnet Transfer&quot;">​</a></h1><p>Magnet transfer က magnet link မှ files download လုပ်ပြီး သင်ရွေးထားတဲ့ cloud storage channel ထဲအလိုအလျောက် upload လုပ်ပါတယ်။</p><p>anime episodes, videos, archives နဲ့ အလားတူ files တွေ transfer လုပ်ဖို့အသုံးဝင်ပါတယ်။ magnet link ကို paste လုပ်ပါ၊ ImgBed က background download task ဖန်တီးပါမယ်။ download ပြီးတဲ့အခါ file ကို ImgBed ထဲ upload လုပ်ပြီး final link က upload list မှာပေါ်ပါမယ်။</p><p><img src="'+e+'" alt="Magnet transfer" loading="lazy"></p><h2 id="ဘယ်နေရာမှာ-သုံးမလဲ" tabindex="-1">ဘယ်နေရာမှာ သုံးမလဲ <a class="header-anchor" href="#ဘယ်နေရာမှာ-သုံးမလဲ" aria-label="Permalink to &quot;ဘယ်နေရာမှာ သုံးမလဲ&quot;">​</a></h2><p>magnet transfer entry က homepage upload area ထဲမှာရှိပါတယ်။</p><p>magnet link ကို input box ထဲ paste လုပ်ပါ၊ <code>Transfer</code> ကိုရွေးပါ၊ ပြီးရင် upload လုပ်ပါ။</p><p><img src="'+t+'" alt="Upload anime" loading="lazy"></p><h2 id="ပထမဆုံးအသုံးမပြုခင်" tabindex="-1">ပထမဆုံးအသုံးမပြုခင် <a class="header-anchor" href="#ပထမဆုံးအသုံးမပြုခင်" aria-label="Permalink to &quot;ပထမဆုံးအသုံးမပြုခင်&quot;">​</a></h2><p>admin panel မှာ magnet transfer ကိုအရင် configure လုပ်ပါ။</p><p>များသောအားဖြင့်လိုအပ်တာ:</p><ol><li>download task run လုပ်ဖို့ GitHub account။</li><li>Google Drive သို့မဟုတ် OneDrive လို cloud upload channel။</li><li>target upload directory။</li><li>task timeout။</li></ol><p>settings အသင့်ဖြစ်ပြီးနောက် homepage ကိုပြန်သွားပြီး magnet link paste လုပ်ကာ transfer စနိုင်ပါတယ်။</p><h2 id="magnet-link-upload-လုပ်ခြင်း" tabindex="-1">Magnet Link Upload လုပ်ခြင်း <a class="header-anchor" href="#magnet-link-upload-လုပ်ခြင်း" aria-label="Permalink to &quot;Magnet Link Upload လုပ်ခြင်း&quot;">​</a></h2><ol><li>homepage upload box ထဲ magnet link paste လုပ်ပါ။</li><li>mode က <code>Transfer</code> ဖြစ်ကြောင်းသေချာပါစေ။</li><li>upload ကိုနှိပ်ပါ။</li><li>ImgBed က magnet task create လုပ်တာကိုစောင့်ပါ။</li><li>task စပြီးနောက် ညာဘက်အောက်ထောင့်က floating <code>Magnet Tasks</code> panel နဲ့ progress ကြည့်ပါ။</li></ol><p>download နဲ့ upload ကအချိန်ယူနိုင်ပါတယ်။ speed က magnet resource, GitHub runtime environment, selected cloud storage channel တို့အပေါ်မူတည်ပါတယ်။</p><p><img src="'+l+'" alt="Magnet downloading" loading="lazy"></p><h2 id="completion-ပြီးနောက်" tabindex="-1">Completion ပြီးနောက် <a class="header-anchor" href="#completion-ပြီးနောက်" aria-label="Permalink to &quot;Completion ပြီးနောက်&quot;">​</a></h2><p>task complete ဖြစ်ပြီးနောက် upload list မှာ file name နဲ့ link ပြပါမယ်။</p><p>videos တွေက video preview ပြပြီး images တွေက image preview ပြပါတယ်။ အခြား files တွေက regular file icon နဲ့ပြပါတယ်။</p><p><img src="'+o+'" alt="Downloaded video" loading="lazy"></p><p>copy လုပ်နိုင်တာတွေ:</p><table tabindex="0"><thead><tr><th>Link Type</th><th>Use Case</th></tr></thead><tbody><tr><td>Original link</td><td>direct file access</td></tr><tr><td>Markdown</td><td>Markdown posts သို့မဟုတ် notes</td></tr><tr><td>HTML</td><td>web page code</td></tr><tr><td>BBCode</td><td>BBCode support လုပ်တဲ့ forums</td></tr></tbody></table><h2 id="magnet-task-panel" tabindex="-1">Magnet Task Panel <a class="header-anchor" href="#magnet-task-panel" aria-label="Permalink to &quot;Magnet Task Panel&quot;">​</a></h2><p>ညာဘက်အောက် magnet task panel က task count, task name, progress, final status ကိုပြပါတယ်။</p><p>Common states:</p><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th></tr></thead><tbody><tr><td>Waiting</td><td>task ဖန်တီးပြီး run ဖို့စောင့်နေသည်။</td></tr><tr><td>Downloading</td><td>magnet resource download လုပ်နေသည်။</td></tr><tr><td>Uploading</td><td>file download ပြီး cloud storage ထဲ upload လုပ်နေသည်။</td></tr><tr><td>Completed</td><td>upload အောင်မြင်ပြီး link copy လုပ်နိုင်သည်။</td></tr><tr><td>Failed</td><td>task မအောင်မြင်ပါ။ message စစ်ပြီးထပ်ကြိုးစားပါ။</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>magnet link တစ်ခုထဲ files အများကြီးပါလျှင် ImgBed က display အတွက် main completed file ကိုဦးစားပေးပါတယ်။</li><li>large files တွေကအချိန်ပိုယူပါတယ်။ page refresh မလုပ်ခင် task ပြီးအောင်စောင့်ပါ။</li><li>magnet resource မှာ available peers မရှိလျှင် အရမ်းနှေးနိုင် သို့မဟုတ် fail ဖြစ်နိုင်ပါတယ်။</li><li>cloud account quota ကုန်လျှင်၊ authorization expire ဖြစ်လျှင်၊ upload directory မှားလျှင် task fail ဖြစ်နိုင်ပါတယ်။</li><li>upload complete ပြီးနောက် video preview ပေါ်ဖို့ seconds အနည်းငယ်ယူနိုင်ပါတယ်။</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="magnet-link-paste-လုပ်ပြီးနောက်-ဘာမှမစဘူး" tabindex="-1">Magnet Link Paste လုပ်ပြီးနောက် ဘာမှမစဘူး <a class="header-anchor" href="#magnet-link-paste-လုပ်ပြီးနောက်-ဘာမှမစဘူး" aria-label="Permalink to &quot;Magnet Link Paste လုပ်ပြီးနောက် ဘာမှမစဘူး&quot;">​</a></h3><p>admin panel မှာ magnet transfer enabled ဖြစ်လား၊ usable GitHub account နဲ့ cloud channel ရွေးထားလား confirm လုပ်ပါ။</p><h3 id="download-အမြဲနှေးတယ်" tabindex="-1">Download အမြဲနှေးတယ် <a class="header-anchor" href="#download-အမြဲနှေးတယ်" aria-label="Permalink to &quot;Download အမြဲနှေးတယ်&quot;">​</a></h3><p>magnet speed က resource ကိုယ်တိုင်အပေါ်မူတည်ပါတယ်။ available peers မရှိလျှင် download အရမ်းနှေး သို့မဟုတ် မဖြစ်နိုင်ပါ။</p><h3 id="upload-ပြီးနောက်-preview-မပေါ်ဘူး" tabindex="-1">Upload ပြီးနောက် Preview မပေါ်ဘူး <a class="header-anchor" href="#upload-ပြီးနောက်-preview-မပေါ်ဘူး" aria-label="Permalink to &quot;Upload ပြီးနောက် Preview မပေါ်ဘူး&quot;">​</a></h3><p>ပထမဆုံး file link ဖွင့်လို့ရလား confirm လုပ်ပါ။ video files တွေက browser ထဲ load ဖို့အချိန်နည်းနည်းလိုနိုင်ပါတယ်၊ သို့မဟုတ် link ကိုတိုက်ရိုက်ဖွင့်နိုင်ပါတယ်။</p><h3 id="task-fail-ဖြစ်ရင်-ဘာစစ်ရမလဲ" tabindex="-1">Task Fail ဖြစ်ရင် ဘာစစ်ရမလဲ? <a class="header-anchor" href="#task-fail-ဖြစ်ရင်-ဘာစစ်ရမလဲ" aria-label="Permalink to &quot;Task Fail ဖြစ်ရင် ဘာစစ်ရမလဲ?&quot;">​</a></h3><p>magnet link valid ဖြစ်လား၊ cloud channel အလုပ်လုပ်လား၊ upload directory မှန်လားစစ်ပါ။ ပြီးရင် task ကိုထပ် submit လုပ်ပါ။</p>',38)])])}const _=n(s,[["render",p]]);export{b as __pageData,_ as default};
